const item = $input.item.json;
const attachmentData = item.attachmentData;

// Nombre y extensión del archivo
const fileName = attachmentData.name || 'attachment';
const fileExtension = fileName.split('.').pop().toLowerCase();
const binaryPropertyName = attachmentData.id || 'attachment_0';

// Email metadata incrustada en attachmentData por Preparar Adjuntos
// Fallback a item.* por si Split Out los pasa también
const emailMessageId = attachmentData.emailMessageId || item.id || item.emailMessageId || '';
const emailFrom = attachmentData.emailFrom || item.from || item.emailFrom || '';
const emailSubject = attachmentData.emailSubject || item.subject || item.emailSubject || '';
const emailDate = attachmentData.emailDate || item.date || item.emailDate || '';

// Binary: Split Out pierde el binary del item padre — recuperar via referencia cruzada
const parentBinary = $('Preparar Adjuntos').item.binary || {};
const thisBinary = parentBinary[binaryPropertyName]
  ? { [binaryPropertyName]: parentBinary[binaryPropertyName] }
  : $input.item.binary || {};

// === SHA-256 file_hash (detección infalible de duplicados, sesión 28) ===
let fileHash = '';
try {
  const crypto = require('crypto');
  const buffer = await this.helpers.getBinaryDataBuffer(0, binaryPropertyName);
  fileHash = crypto.createHash('sha256').update(buffer).digest('hex');
} catch (e) {
  console.error('[Normalizar Adjunto] SHA-256 falló:', e.message);
  // Fallback: fingerprint hash de metadata para que dedup siga funcionando
  // (no es el SHA-256 real del archivo pero es único por adjunto-en-email)
  try {
    const crypto = require('crypto');
    const fallbackSrc = String(fileName || '') + '|' + String(fileExtension || '') + '|' + String(emailFrom || '') + '|' + String(item.attachmentData && item.attachmentData.fileSize || '0');
    fileHash = crypto.createHash('sha256').update(fallbackSrc).digest('hex');
    console.warn('[Normalizar Adjunto] Usando fallback hash basado en metadata para', fileName);
  } catch (e2) {
    fileHash = '';
  }
}

return {
  json: {
    ...item,
    fileName,
    fileExtension,
    binaryPropertyName,
    originalFileName: fileName,
    emailMessageId,
    emailFrom,
    emailSubject,
    emailDate,
    fileHash
  },
  binary: thisBinary
};

const item = $input.item.json;
const binary = $input.item.binary || {};

const ext = (item.fileExtension || '').toLowerCase();

// Solo se procesan PDFs e imágenes. Word, Excel, ZIP, XML, etc. se descartan siempre:
// no son procesables por GPT vision y en el contexto de facturas son irrelevantes.
const supported = ['pdf', 'jpg', 'jpeg', 'png', 'gif', 'bmp', 'tiff', 'webp', 'heic'];
if (!supported.includes(ext)) {
  console.log('Descartado por extensión no soportada:', ext, item.fileName);
  return null;
}

// Filtro de tamaño: imágenes < 10 KB son casi siempre logos/firmas/iconos
const binKey = item.binaryPropertyName || 'attachment_0';
const bin = binary[binKey];
const fileSizeRaw = bin?.fileSize;
const fileSizeBytes = typeof fileSizeRaw === 'number' ? fileSizeRaw :
  typeof fileSizeRaw === 'string' ? parseFloat(fileSizeRaw) * (fileSizeRaw.includes('kB') ? 1024 : fileSizeRaw.includes('MB') ? 1048576 : 1) : 0;

const isImageExt = ['jpg','jpeg','png','gif','bmp','tiff','webp','heic'].includes(ext);
if (isImageExt && fileSizeBytes > 0 && fileSizeBytes < 10240) {
  console.log('Saltando imagen pequeña (<10KB):', item.fileName, fileSizeBytes, 'bytes');
  return null;
}

return {
  json: { ...item, fileExtension: ext, fileSizeBytes },
  binary: binary
};

// =============================================================================
// Router Carpeta Destino — versión sesión 31 v2 (1/05/2026 madrugada)
// Lookup HTTP inline (httpCustomAuth) a project_subfolders. NO requiere nodo
// nuevo en el path. Una HTTP call por item (Supabase aguanta sobradamente).
// =============================================================================
const item = $input.item.json;
const cfg = $('Config').first().json;

const docType = (item.tipo || item.doc_type || '').toLowerCase();
const proyectoCode = item.proyecto_code || '';
const projectId = item.project_id || item.projectId || null;
const categoriaGasto = (item.categoria_gasto || '').toLowerCase();

// Mapping doc_type → nombre subcarpeta, por tipo proyecto
const SUBFOLDER_MAP = {
  OBR: { factura:'03_Facturas', ticket:'03_Facturas', rectificativa:'03_Facturas', abono:'03_Facturas', justificante_pago:'03_Facturas', presupuesto:'01_Presupuestos', proforma:'04_Proformas', albaran:'05_Albaranes', certificado:'06_Certificados', certificacion:'06_Certificados', contrato:'02_Contratos', licencia:'08_Licencias_permisos', seguro:'09_Seguros', informe:'07_Documentacion_tecnica', escritura:'02_Contratos', nota_simple:'02_Contratos' },
  CDU: { factura:'05_Facturas', ticket:'05_Facturas', rectificativa:'05_Facturas', abono:'05_Facturas', justificante_pago:'05_Facturas', presupuesto:'09_Presupuestos', proforma:'06_Proformas', albaran:'07_Albaranes', certificado:'08_Certificados', certificacion:'08_Certificados', contrato:'04_Contratos', licencia:'03_Licencias_permisos', seguro:'10_Seguros', informe:'02_Proyecto_tecnico', escritura:'13_Registro_propiedad', nota_simple:'13_Registro_propiedad', modelo_fiscal:'16_Cierre_fiscal' },
  OBN: { factura:'07_Facturas', ticket:'07_Facturas', rectificativa:'07_Facturas', abono:'07_Facturas', justificante_pago:'07_Facturas', presupuesto:'11_Presupuestos', proforma:'08_Proformas', albaran:'09_Albaranes', certificado:'10_Certificados', certificacion:'10_Certificados', contrato:'06_Contratos', licencia:'04_Licencias_permisos', seguro:'13_Seguros', informe:'03_Proyecto_tecnico', escritura:'01_Suelo', nota_simple:'01_Suelo', modelo_fiscal:'21_Cierre_fiscal' },
  PRO: { factura:'07_Facturas', ticket:'07_Facturas', rectificativa:'07_Facturas', abono:'07_Facturas', justificante_pago:'07_Facturas', presupuesto:'11_Presupuestos', proforma:'08_Proformas', albaran:'09_Albaranes', certificado:'10_Certificados', certificacion:'10_Certificados', contrato:'06_Contratos', licencia:'04_Licencias_permisos', seguro:'13_Seguros', informe:'03_Proyecto_tecnico', escritura:'01_Suelo', nota_simple:'01_Suelo', modelo_fiscal:'23_Cierre_fiscal' },
  FLP: { factura:'04_Reforma', ticket:'04_Reforma', rectificativa:'04_Reforma', abono:'04_Reforma', justificante_pago:'04_Reforma', presupuesto:'04_Reforma', proforma:'04_Reforma', albaran:'04_Reforma', certificado:'04_Reforma', certificacion:'04_Reforma', contrato:'02_Compra', licencia:'04_Reforma', seguro:'05_Gastos_tenencia', informe:'04_Reforma', escritura:'02_Compra', nota_simple:'02_Compra' },
};
const FLP_CATEGORIA_OVERRIDE = {
  suministros:'05_Gastos_tenencia', comunidad_propietarios:'05_Gastos_tenencia', tributos_locales:'05_Gastos_tenencia', seguros:'05_Gastos_tenencia', financiero:'05_Gastos_tenencia', alquiler:'05_Gastos_tenencia', gestoria_asesoria:'05_Gastos_tenencia', software_oficina:'05_Gastos_tenencia', desplazamientos_dietas:'05_Gastos_tenencia', notaria_registro:'02_Compra', comisiones_intermediacion:'02_Compra', marketing_publicidad:'06_Venta',
};

// Casos especiales: nómina y modelo_fiscal Cathedral → ADMINISTRACION
if (docType === 'nomina') {
  return {
    json: { ...item, targetFolderId: '113BL-yElcr7Icx67N3A0XWHzXsMQnfS7', folderName: 'ADMINISTRACION/Laboral', isLowConfidence: false, _routed_via: 'admin_laboral' },
    binary: $input.item.binary || {},
  };
}
if (docType === 'modelo_fiscal' && (item.nif_emisor === $('Config').first().json.CATHEDRAL_NIF || item.cif_empresa === $('Config').first().json.CATHEDRAL_NIF)) {
  return {
    json: { ...item, targetFolderId: '19kU5SJNLF-PTl9GenTqBOwPgha4XRITM', folderName: 'ADMINISTRACION/Fiscal', isLowConfidence: false, _routed_via: 'admin_fiscal' },
    binary: $input.item.binary || {},
  };
}

function resolveSubfolderName() {
  if (!proyectoCode) return null;
  const prefix = proyectoCode.split('-')[0].toUpperCase();
  const map = SUBFOLDER_MAP[prefix];
  if (!map) return null;
  if (prefix === 'FLP' && categoriaGasto && FLP_CATEGORIA_OVERRIDE[categoriaGasto]) {
    return FLP_CATEGORIA_OVERRIDE[categoriaGasto];
  }
  return map[docType] || null;
}

const subfolderName = resolveSubfolderName();
let targetFolderId = null;
let folderName = null;
let routedVia = 'fallback';

// Lookup HTTP inline a project_subfolders si tenemos project_id + subfolderName
if (projectId && subfolderName) {
  try {
    const response = await this.helpers.httpRequestWithAuthentication.call(
      this,
      'httpCustomAuth',
      {
        method: 'GET',
        url: 'https://cpqsnajuypgjjapvbqsr.supabase.co/rest/v1/project_subfolders',
        qs: {
          project_id: `eq.${projectId}`,
          subfolder_name: `eq.${subfolderName}`,
          select: 'drive_folder_id',
        },
        json: true,
        timeout: 5000,
      },
    );
    const rows = Array.isArray(response) ? response : [];
    if (rows.length > 0 && rows[0].drive_folder_id) {
      targetFolderId = rows[0].drive_folder_id;
      folderName = `PROYECTOS/${proyectoCode}/${subfolderName}`;
      routedVia = 'project_subfolder';
    }
  } catch (e) {
    // lookup falla → silently fall back to FOLDER_MAP
    routedVia = 'fallback_lookup_error';
  }
}

// Fallback FOLDER_MAP del Config (carpetas planas _PENDIENTE_CLASIFICAR)
if (!targetFolderId) {
  const folder = cfg.FOLDER_MAP[docType] || cfg.FOLDER_MAP['_default'];
  targetFolderId = folder.id;
  folderName = folder.name;
}

// AI confidence
const ai_confidence = typeof item.ai_confidence === 'number' ? item.ai_confidence : (typeof item.confianza === 'number' ? item.confianza : 0.3);
const isLowConfidence = ai_confidence < cfg.LOW_CONFIDENCE_THRESHOLD;

// Recuperar _attachment_b64 desde upstream si se perdieron (igual que versión anterior)
let attachment_b64 = item._attachment_b64;
let attachment_mime = item._attachment_mime;
let binaryPropertyName = item.binaryPropertyName;
let fileNameFromItem = item.fileName || item.originalFileName;
if (!attachment_b64) {
  try {
    const cv = $('Adaptador Webhook→Pipeline').itemMatching($itemIndex).json;
    attachment_b64 = cv._attachment_b64;
    attachment_mime = attachment_mime || cv._attachment_mime;
    binaryPropertyName = binaryPropertyName || cv.binaryPropertyName;
    fileNameFromItem = fileNameFromItem || cv.fileName || cv.originalFileName;
  } catch (e) { /* ignore */ }
}

// Generar nombre archivo normalizado
const proveedor = (item.proveedor || 'desconocido').toLowerCase().replace(/[^a-z0-9]/g, '_').substring(0, 20);
const fecha = item.fecha_emision ? item.fecha_emision.split('T')[0].replace(/-/g, '') : new Date().toISOString().split('T')[0].replace(/-/g, '');
const numFactura = (item.numero_factura || '').replace(/[^a-zA-Z0-9_\-]/g, '_').substring(0, 30);
const ext = (fileNameFromItem || 'archivo.pdf').split('.').pop().toLowerCase();
// Sanitizar TODOS los componentes a [a-zA-Z0-9._-] estricto. Garantiza que el
// queryString de Drive Search Existing nunca tendrá caracteres que rompan la API.
function safeName(s) { return String(s||'').replace(/[^a-zA-Z0-9_-]/g, '_').replace(/_+/g, '_').replace(/^_|_$/g, ''); }
const safeFecha = safeName(fecha);
const safeProveedor = safeName(proveedor).substring(0,20);
const safeNumFactura = safeName(numFactura).substring(0,30);
const safeExt = safeName(ext).substring(0,5) || 'pdf';
const newFileName = [safeFecha, safeProveedor, safeNumFactura].filter(Boolean).join('_') + '.' + safeExt;
const fileHash = item.fileHash || `${item.emailMessageId || ''}_${fileNameFromItem || ''}_${item.importe_total || 0}`;

// Reconstruct binary
let binary = $input.item.binary || {};
if (attachment_b64) {
  const buf = Buffer.from(attachment_b64, 'base64');
  const propName = binaryPropertyName || 'attachment_0';
  const prepared = await this.helpers.prepareBinaryData(buf, fileNameFromItem || newFileName, attachment_mime || 'application/pdf');
  binary = { [propName]: prepared };
}

const { _attachment_b64, _attachment_mime, ...itemClean } = item;

return {
  json: {
    ...itemClean,
    targetFolderId,
    folderName,
    isLowConfidence,
    newFileName,
    fileHash,
    binaryPropertyName: binaryPropertyName || 'attachment_0',
    _routed_subfolder_name: subfolderName,
    _routed_via: routedVia,
  },
  binary: binary,
};

// ─── Hook del verificador algorítmico (sesión 25) ───

// === Parser regex direcciones (fallback cuando GPT no desglosa) ===
// Inserta antes de la creación del row Supabase. Se usa como fallback.



const _PROVINCIA_BY_CP = {
  '01':'Álava','02':'Albacete','03':'Alicante','04':'Almería','05':'Ávila',
  '06':'Badajoz','07':'Baleares','08':'Barcelona','09':'Burgos','10':'Cáceres',
  '11':'Cádiz','12':'Castellón','13':'Ciudad Real','14':'Córdoba','15':'A Coruña',
  '16':'Cuenca','17':'Girona','18':'Granada','19':'Guadalajara','20':'Gipuzkoa',
  '21':'Huelva','22':'Huesca','23':'Jaén','24':'León','25':'Lleida',
  '26':'La Rioja','27':'Lugo','28':'Madrid','29':'Málaga','30':'Murcia',
  '31':'Navarra','32':'Ourense','33':'Asturias','34':'Palencia','35':'Las Palmas',
  '36':'Pontevedra','37':'Salamanca','38':'Santa Cruz de Tenerife','39':'Cantabria',
  '40':'Segovia','41':'Sevilla','42':'Soria','43':'Tarragona','44':'Teruel',
  '45':'Toledo','46':'Valencia','47':'Valladolid','48':'Bizkaia','49':'Zamora',
  '50':'Zaragoza','51':'Ceuta','52':'Melilla'
};
function _parseAddressES(fullAddr) {
  if (!fullAddr || typeof fullAddr !== 'string') return {};
  const out = {};
  const s = fullAddr.trim();
  if (!s) return out;

  // Código postal: 5 dígitos consecutivos
  const cpMatch = s.match(/\b(\d{5})\b/);
  if (cpMatch) {
    out.codigo_postal = cpMatch[1];
    const prov = _PROVINCIA_BY_CP[cpMatch[1].slice(0, 2)];
    if (prov) out.provincia = prov;
  }

  // Vía + número: arranca por palabras (no dígitos), seguido de número.
  // Ej. "Paseo Castellana 40", "Calle Mayor 23"
  const viaMatch = s.match(/^([A-ZÁÉÍÓÚÑ][^\d,]+?)\s+(\d{1,4}(?:\s*[a-zA-Z])?)(?:\s*[,-]|\s|$)/i);
  if (viaMatch) {
    out.via_publica = viaMatch[1].trim().replace(/\s+/g, ' ');
    out.numero = viaMatch[2].trim();
  }

  // Municipio: bloque que tiene "<CP> <Municipio>"
  const muniMatch = s.match(/\b\d{5}\s+([A-ZÁÉÍÓÚÑ][a-zA-ZÁÉÍÓÚÑáéíóúñ\s'.\-]+?)(?:\s*,|\s*$|\s+\(|\s+ESPAÑA|\s+ES\b)/);
  if (muniMatch) {
    out.municipio = muniMatch[1].trim().replace(/\s+/g, ' ');
  }

  // Resto dirección: lo que quede entre número y CP (piso, escalera, puerta…)
  if (out.numero && out.codigo_postal) {
    const idxNum = s.indexOf(out.numero);
    const idxCP = s.indexOf(out.codigo_postal);
    if (idxNum > -1 && idxCP > idxNum) {
      const between = s.slice(idxNum + out.numero.length, idxCP).trim();
      // Limpiar comas/separadores
      const cleaned = between.replace(/^[,\s\-]+|[,\s\-]+$/g, '').trim();
      if (cleaned && cleaned.length < 100) out.resto_direccion = cleaned;
    }
  }

  return out;
}


// Si el nodo "Llamar Verificador" se ejecutó, leemos su resultado y lo aplicamos
// al payload final marcando needs_review + concatenando razones en ai_razones.
let __verifierResult = null;
try {
  __verifierResult = $('Llamar Verificador').itemMatching($itemIndex).json;
} catch (e) {
  // Verificador no ejecutado o falló — continuar sin él (defense-in-depth)
}
function __applyVerifier(payload) {
  if (!__verifierResult) return payload;
  if (__verifierResult.needs_review) {
    payload.needs_review = true;
    const razones = (__verifierResult.review_reasons || []).map(r => `§VERIFICADOR:${r}`);
    payload.ai_razones = (payload.ai_razones || []).concat(razones);
  }
  return payload;
}
// ─── Fin hook ───


// ─── Hook Mistral OCR (sesión 28, Fase D) ───
let __mistralDiscrepancies = [];
try {
  const r = $input.item.json;
  __mistralDiscrepancies = r._mistral_discrepancies || [];
} catch (e) {
  // Mistral OCR no se ejecutó - continuar sin
}
function __applyMistral(payload) {
  if (!payload || __mistralDiscrepancies.length === 0) return payload;
  const critical = __mistralDiscrepancies.some(d => /nif_emisor|importe_total|empresa_cif/i.test(d));
  if (critical) payload.needs_review = true;
  payload.ai_razones = (payload.ai_razones || []).concat(__mistralDiscrepancies);
  return payload;
}
// ─── Fin hook Mistral ───


// ─── Validación checksum NIF/NIE/CIF (algoritmos oficiales españoles) ───
function _validateSpanishId(id) {
  if (!id || typeof id !== 'string') return { valid: false, type: 'unknown', reason: 'vacío o no string' };
  const clean = id.toUpperCase().trim().replace(/[\s-]/g, '');
  // NIF: 8 dígitos + letra
  // NIE: X|Y|Z + 7 dígitos + letra
  // CIF: letra + 7 dígitos + dígito o letra control
  const LETRAS = 'TRWAGMYFPDXBNJZSQVHLCKE';
  if (/^[XYZ][0-9]{7}[A-Z]$/.test(clean)) {
    // NIE
    const prefix = { X: '0', Y: '1', Z: '2' }[clean[0]];
    const num = parseInt(prefix + clean.substring(1, 8));
    const expected = LETRAS[num % 23];
    return { valid: clean[8] === expected, type: 'NIE', expected_letter: expected, given_letter: clean[8], reason: clean[8] === expected ? null : `letra control esperada '${expected}', recibida '${clean[8]}'` };
  }
  if (/^[0-9]{8}[A-Z]$/.test(clean)) {
    // NIF
    const num = parseInt(clean.substring(0, 8));
    const expected = LETRAS[num % 23];
    return { valid: clean[8] === expected, type: 'NIF', expected_letter: expected, given_letter: clean[8], reason: clean[8] === expected ? null : `letra control esperada '${expected}', recibida '${clean[8]}'` };
  }
  if (/^[ABCDEFGHJNPQRSUVW][0-9]{7}[0-9A-J]$/.test(clean)) {
    // CIF (empresas)
    const digits = clean.substring(1, 8);
    let sumPar = 0, sumImpar = 0;
    for (let i = 0; i < 7; i++) {
      const d = parseInt(digits[i]);
      if (i % 2 === 0) {
        // Posición impar (1, 3, 5, 7) en numeración 1-indexed
        const doubled = d * 2;
        sumImpar += Math.floor(doubled / 10) + (doubled % 10);
      } else {
        sumPar += d;
      }
    }
    const total = sumPar + sumImpar;
    const controlNum = (10 - (total % 10)) % 10;
    const controlLetter = 'JABCDEFGHI'[controlNum];
    const provided = clean[8];
    const validNum = provided === String(controlNum);
    const validLetter = provided === controlLetter;
    // Las primeras letras (P, Q, R, S, W) requieren letra; (A, B, E, H) requieren número; otras admiten ambos
    const valid = validNum || validLetter;
    return { valid, type: 'CIF', expected_letter: controlLetter, expected_num: String(controlNum), given_letter: provided, reason: valid ? null : `control esperado '${controlLetter}' o '${controlNum}', recibido '${provided}'` };
  }
  return { valid: false, type: 'unknown', reason: 'formato no reconocido (esperado: NIF 12345678X, NIE X1234567Y, CIF B12345678)' };
}


// ═══════════════════════════════════════════════════════════════
// EARLY ROUTING: si es payrolls o payroll_summaries, manejar aquí
// y NO ejecutar el resto (que está pensado para invoices/documents)
// ═══════════════════════════════════════════════════════════════
const _earlyItem = $input.item.json;
const _earlyTarget = _earlyItem.target_table || 'invoices';
const _earlyR = _earlyItem.resultado_vision || _earlyItem.resultado_filesapi || {};

function _parseAmt(v) {
  if (v === null || v === undefined || v === '') return null;
  const n = typeof v === 'number' ? v : parseFloat(String(v).replace(/[€\s]/g,'').replace(/\./g,'').replace(',','.'));
  return isNaN(n) ? null : n;
}
function _parseDate(v) {
  if (!v) return null;
  const m1 = String(v).match(/^(\d{4})-(\d{2})-(\d{2})/);
  if (m1) return `${m1[1]}-${m1[2]}-${m1[3]}`;
  const m2 = String(v).match(/^(\d{1,2})[\/-](\d{1,2})[\/-](\d{2,4})/);
  if (m2) {
    const yr = m2[3].length === 2 ? '20' + m2[3] : m2[3];
    return `${yr}-${m2[2].padStart(2,'0')}-${m2[1].padStart(2,'0')}`;
  }
  return null;
}

if (_earlyTarget === 'payrolls') {
  const nominas = Array.isArray(_earlyR.nominas) ? _earlyR.nominas : [];
  if (nominas.length === 0) {
    // No hay nóminas extraídas → marcar error
    return {
      json: {
        ..._earlyItem,
        target_table: 'payrolls',
        supabase_payload: null,
        _payroll_error: 'GPT no devolvió array nominas',
        needs_review: true
      },
      binary: $input.item.binary
    };
  }

  // Mapear cada nómina a un item separado (split → N filas en INSERT)
  const items = nominas.map((nom, idx) => {
    const periodoDesde = _parseDate(nom.periodo_desde);
    const periodoHasta = _parseDate(nom.periodo_hasta);
    let mes = nom.periodo_mes;
    let anio = nom.periodo_anio;
    if (!mes && periodoHasta) mes = parseInt(periodoHasta.split('-')[1]);
    if (!anio && periodoHasta) anio = parseInt(periodoHasta.split('-')[0]);

    const payload = {
      // Empresa
      empresa_nombre: nom.empresa_nombre || null,
      empresa_cif: nom.empresa_cif || null,
      empresa_domicilio: nom.empresa_domicilio || null,
      empresa_cp: nom.empresa_cp || null,
      empresa_localidad: nom.empresa_localidad || null,
      empresa_cuenta_cotizacion_ss: nom.empresa_cuenta_cotizacion_ss || null,
      // Trabajador
      trabajador_nombre: nom.trabajador_nombre || null,
      trabajador_nif: nom.trabajador_nif || null,
      trabajador_num_afiliacion_ss: nom.trabajador_num_afiliacion_ss || null,
      trabajador_categoria: nom.trabajador_categoria || null,
      trabajador_grupo_cotizacion: nom.trabajador_grupo_cotizacion ? parseInt(nom.trabajador_grupo_cotizacion) : null,
      trabajador_fecha_antiguedad: _parseDate(nom.trabajador_fecha_antiguedad),
      trabajador_centro: nom.trabajador_centro || null,
      trabajador_departamento: nom.trabajador_departamento || null,
