// Prepara payload de placeholder de error para insertar en invoices.
// Este nodo se ejecuta cuando GPT-Vision agota retries (3) o falla con error controlado.
// Asegura que el documento NO desaparezca en silencio: queda visible en /admin con review_status='error'.

// El input puede ser un array (de exceptions_log) o un item normal del workflow

// SOURCE dinámico según origen webhook (admin upload | worker portal | gmail)
function determinarSource(emailAccount, sourceFlag) {
  if (sourceFlag === 'webhook_admin_upload') {
    if (emailAccount === 'worker_upload') return 'worker_portal';
    return 'manual_upload';  // admin_upload default
  }
  if (sourceFlag === 'webhook_reprocess') return 'reprocesador';
