// matemática facturas (base+IVA=total) y nóminas (devengo-deducc=líquido).
//
// Endpoint: POST https://cathedralgroup.es/api/verifier
// Espera: { document_type: '...', fields: {...} }
// Devuelve: { overall_valid, needs_review, review_reasons[], field_validations[] }

const item = $input.item.json;
const r = item.resultado_vision || item.resultado_filesapi || {};
const tipo = (item.tipo || r.tipo || 'factura').toLowerCase();

// Si es nomina_lote, el verificador se llama por cada nómina; aquí
