// Adaptador Webhook → Pipeline general (sesión 30 fix, binary-typed).
// b64 NO va en json — n8n lo gestiona en filesystem para evitar OOM.
// SHA-256 calculado replicando el patrón Normalizar Adjunto del path Gmail.
//
// Si binary se pierde por HTTP intermedios, recuperar con cross-node ref a este nodo
// (ver `Construir Prompt` que reconstruye binary antes de Convertir a Visión).

// V2 (15/05/2026): leer body desde Webhook node directamente.
// $input es INSERT Idempotency response (sin attachment_b64). $('Webhook Reprocesador').first().json.body tiene payload original.
const webhookData = $('Webhook Reprocesador').first().json;
const body = webhookData.body || $input.item.json.body || $input.item.json;
const messageId = body.message_id || '';
const account = body.gmail_account || '';
const fromAddress = body.from_address || '';
const subject = body.subject || '';
const receivedAt = body.received_at || '';
const emailBody = (body.body || '').toString().substring(0, 5000);
const filename = body.filename || ('attachment_' + Date.now());
const mimeType = body.mime_type || 'application/octet-stream';
const b64 = body.attachment_b64 || '';

if (!messageId || !b64 || !account) {
  throw new Error('Missing required fields: message_id, attachment_b64, gmail_account');
}

const fileExtension = (filename.split('.').pop() || '').toLowerCase();
const binaryPropertyName = 'attachment_0';
const buffer = Buffer.from(b64, 'base64');

const binData = await this.helpers.prepareBinaryData(buffer, filename, mimeType);

let fileHash = '';
try {
  const crypto = require('crypto');
  fileHash = crypto.createHash('sha256').update(buffer).digest('hex');
} catch (e) {
  console.error('[Adaptador Webhook] SHA-256 falló:', e.message);
  fileHash = '';
}

return {
  json: {
    fileName: filename,
    fileExtension,
    binaryPropertyName,
    originalFileName: filename,
    emailMessageId: messageId,
    emailFrom: fromAddress,
    emailSubject: subject,
    emailDate: receivedAt,
    emailBody,
    id: binaryPropertyName,
    name: filename,
    mimeType,
    fileSize: buffer.length,
    fileHash,
    emailAccount: account,
    _source: 'webhook_reprocess',
    _injected_at: new Date().toISOString(),
  },
  binary: { [binaryPropertyName]: binData }
};

// === Cascada Entidad — Preparar Upsert (V3 sesión 9/05/2026 noche tarde) ===
// (mantiene el nombre "Cascada Supplier" por compatibilidad con conexiones)
//
// V3: separación de responsabilidades. Este Code SOLO prepara el payload del
// upsert. La llamada HTTP la hace el siguiente nodo "Upsert Entidad" usando
// la credencial httpCustomAuth (la función helpers.httpRequestWithAuthentication
// no funciona en Code Nodes — bug de n8n descubierto en sesión 9/05).
//
// Output:
// - direction='emitida'  → _entity_table='clients',  _entity_unique='nif_cif'
// - direction='recibida' → _entity_table='suppliers', _entity_unique='nif'
// - _entity_should_skip=true cuando NIF inválido o NIF Cathedral

const item = $('Preparar Verificador').item.json;
const cfg = $('Config').first().json;
const direction = item.direction || 'recibida';
const CATHEDRAL_NIF = (cfg.CATHEDRAL_NIF || 'B19761915').toUpperCase();
const SUPABASE_URL = cfg.SUPABASE_URL || 'https://cpqsnajuypgjjapvbqsr.supabase.co/rest/v1';

// Validar NIF a través del verificador algorítmico si está disponible
function isNifValid(nif) {
  if (!nif || nif.length < 9) return false;
  if (nif === CATHEDRAL_NIF) return false; // Nunca crear Cathedral como entidad externa
  try {
    const verifier = $('Llamar Verificador').item.json;
    const reasons = (verifier?.review_reasons || []);
    return !reasons.some(r => /NIF|CIF|NIE/i.test(String(r)));
  } catch (e) {
    return true;
  }
}

// Inferir tipo cliente por estructura del NIF (DNI/NIE → particular, CIF → empresa)
function inferClientType(nif) {
  if (!nif) return null;
  const n = nif.toUpperCase();
  // CIF: empieza por A-H, J-N, P-S, U, V, W (8 dígitos + letra/dígito control)
  if (/^[ABCDEFGHJNPQRSUVW]/.test(n)) return 'empresa';
  // NIE: X/Y/Z + 7 dígitos + letra
  if (/^[XYZ]\d{7}[A-Z]$/.test(n)) return 'particular';
  // DNI: 8 dígitos + letra
  if (/^\d{8}[A-Z]$/.test(n)) return 'particular';
  return null;
}

let entity_table = null;
let entity_unique = null;
let entity_body = null;
let should_skip = false;
let skip_reason = '';

if (direction === 'emitida') {
  // === FACTURA EMITIDA → upsert CLIENTE ===
  const nif = (item.nif_receptor || '').toString().trim().toUpperCase().replace(/[\s-]/g, '');
  const name = (item.nombre_receptor || '').toString().trim();

  if (!isNifValid(nif)) {
    should_skip = true;
    skip_reason = nif === CATHEDRAL_NIF ? 'cathedral_nif_skip' : 'nif_inválido_o_corto';
  } else if (!name) {
    should_skip = true;
    skip_reason = 'sin_nombre_receptor';
  } else {
    entity_table = 'clients';
    entity_unique = 'nif_cif';
    const inferredType = item.cliente_tipo || inferClientType(nif);
    entity_body = {
      nif_cif: nif,
      name: name,
      ...(inferredType ? { type: inferredType } : {}),
      ...(item.cliente_direccion ? { address: item.cliente_direccion } : {}),
      ...(item.cliente_ciudad ? { city: item.cliente_ciudad } : {}),
      ...(item.cliente_telefono ? { phone: item.cliente_telefono } : {}),
      ...(item.cliente_email ? { email: item.cliente_email } : {}),
      source: 'auto_factura_emitida',
    };
  }
} else {
  // === FACTURA RECIBIDA → upsert PROVEEDOR ===
  const nif = (item.nif_emisor || item.nif_proveedor || item.supplier_nif || '').toString().trim().toUpperCase().replace(/[\s-]/g, '');
  const name = (item.empresa || item.proveedor || '').toString().trim();

  if (!isNifValid(nif)) {
    should_skip = true;
    skip_reason = nif === CATHEDRAL_NIF ? 'cathedral_nif_skip' : 'nif_inválido_o_corto';
  } else if (!name) {
    should_skip = true;
    skip_reason = 'sin_empresa';
  } else {
    entity_table = 'suppliers';
    entity_unique = 'nif';
    entity_body = {
      nif: nif,
      name: name,
      ...(item.direccion_emisor ? { address: item.direccion_emisor } : {}),
    };
  }
}

const upsert_url = entity_table
  ? `${SUPABASE_URL}/${entity_table}?on_conflict=${entity_unique}`
  : null;

console.log(`[Cascada Supplier V3] direction=${direction} table=${entity_table || 'skip'} reason=${skip_reason || 'ok'}`);

return {
  json: {
    ...item,
    _entity_table: entity_table,
    _entity_unique_field: entity_unique,
    _entity_body: entity_body,
    _entity_upsert_url: upsert_url,
    _entity_should_skip: should_skip,
    _entity_skip_reason: skip_reason,
    // Compatibilidad con código que aún lee supplier_id_resolved (lo poblará Resolver Entidad ID)
    supplier_id_resolved: null,
    client_id_resolved: null,
    _entity_action: 'pending_upsert',
  },
  binary: $('Preparar Verificador').item.binary,
};

// Aplicar Fuzzy Razones — anti-duplicado por proveedor + importe + fecha cercana
// FIX SESIÓN 10/05 (auditoría profunda Bug 2): si hay matches fuzzy, MARCAR needs_review
// (antes solo propagaba _fuzzy_candidates sin acción → capa decorativa)

const item = $input.item.json;
const candidates = item._fuzzy_candidates || [];
const count = candidates.length;

const out = { ...item, _fuzzy_candidates: candidates, _fuzzy_count: count };

if (count > 0) {
  // Bloquear inserción automática: marcar needs_review + razón
  out.needs_review = true;
  const razones = (item.ai_razones || []).slice();
  const detalle = candidates
    .slice(0, 3)
    .map(c => `id=${c.id} nº=${c.number || '?'} importe=${c.amount_total || c.total || '?'}€ fecha=${c.issue_date || '?'}`)
    .join(' | ');
  razones.push(`§FUZZY:${count} match(es) similar(es) en ventana 20d ±0.5%: ${detalle}`);
  out.ai_razones = razones;
  console.log(`[Fuzzy] BLOQUEAR review ${count} candidatos similares: ${detalle}`);
} else {
  console.log('[Fuzzy] Sin candidatos similares — pasa');
}

return { json: out, binary: $input.item.binary };

// Reusar archivo existente en Drive: devolver estructura compatible con Drive Upload output
// El nodo Upload file devuelve {id, name, webViewLink, ...} desde Drive API.
// Aquí extraemos el primer match del Drive Search Existing y lo formateamos igual.
const search = $input.item.json;
const meta = $('Router Carpeta Destino').item.json;
const binary = $('Router Carpeta Destino').item.binary;
return {
  json: {
    ...meta,
    id: search.id,
    name: search.name,
    webViewLink: search.webViewLink || `https://drive.google.com/file/d/${search.id}/view`,
    _drive_dedup: 'reused-existing'
  },
  binary
};

// V10 (19/05/2026): support admin/worker upload paths + fallback _attachment_b64 cross-node reconstruction
const router = $('Router Carpeta Destino').first();

async function getVisionBinary() {
  // Path 1: Gmail (Adaptador Webhook→Pipeline)
  try {
    const ref = $('Adaptador Webhook→Pipeline').itemMatching($itemIndex);
    if (ref?.binary && Object.keys(ref.binary).length > 0) return ref.binary;
  } catch (e) {}
  // Path 2: Admin/Worker upload (Adaptador Admin Upload)
  try {
    const ref = $('Adaptador Admin Upload').itemMatching($itemIndex);
    if (ref?.binary && Object.keys(ref.binary).length > 0) return ref.binary;
  } catch (e) {}
  // Fallback: reconstruir desde _attachment_b64
  let b64 = null;
  for (const nm of ['Adaptador Admin Upload', 'Adaptador Webhook→Pipeline']) {
    try {
      const ref = $(nm).first().json;
      if (ref?._attachment_b64) { b64 = ref._attachment_b64; break; }
    } catch (e) {}
  }
  if (!b64) return {};
  const filename = router.json?.newFileName || router.json?.fileName || 'file.jpg';
  const mimeType = router.json?.mime_type || 'image/jpeg';
  const buffer = Buffer.from(b64, 'base64');
  const binData = await this.helpers.prepareBinaryData(buffer, filename, mimeType);
  return { attachment_0: binData };
}

const visionBinary = await getVisionBinary();
return {
  json: router.json || {},
  binary: visionBinary,
  pairedItem: { item: $itemIndex }
};

// === Resolver Entidad ID (V3 sesión 9/05/2026 noche tarde) ===
// Lee la respuesta del nodo "Upsert Entidad" (HTTP Request a Supabase) y pega
// el ID resultante en el item como `client_id_resolved` o `supplier_id_resolved`
// según direction.
//
// Si el upsert falló o no se ejecutó (skip), devuelve los IDs en null sin romper.

const upsertResponse = $input.item.json;
const item = $('Cascada Supplier').itemMatching($itemIndex).json;
const direction = item.direction || 'recibida';

let entityId = null;
let action = 'no_response';

// PostgREST con Prefer: return=representation devuelve un array con el row
if (Array.isArray(upsertResponse) && upsertResponse.length > 0 && upsertResponse[0]?.id) {
  entityId = upsertResponse[0].id;
  action = 'upserted';
} else if (upsertResponse?.id) {
  entityId = upsertResponse.id;
  action = 'upserted';
} else if (upsertResponse?.code || upsertResponse?.message) {
  // Error del HTTP (devolvió un error PostgREST)
  action = 'error: ' + (upsertResponse.message || upsertResponse.code || 'unknown').slice(0, 100);
}

const result = {
  ...item,
  supplier_id_resolved: direction === 'recibida' ? entityId : null,
  client_id_resolved:   direction === 'emitida'  ? entityId : null,
  _entity_action: action,
  _entity_resolved_id: entityId,
};

console.log(`[Resolver Entidad ID] direction=${direction} action=${action} id=${entityId}`);

return {
  json: result,
  binary: $('Cascada Supplier').itemMatching($itemIndex).binary,
};

// Aplicar Score Forensic al item
// Lee response del RPC + item original; si score<50 PATCH review_status y razones.
const rpcResponse = $input.item.json;
const original = $('Registrar en Supabase').item.json;
const supabaseId = original.supabase_id;

let score = null;
let alerts = [];
let forensicId = null;

// PostgREST devuelve [{score, all_alerts, forensic_id}]
if (Array.isArray(rpcResponse) && rpcResponse[0]) {
  score = rpcResponse[0].score;
  alerts = rpcResponse[0].all_alerts || [];
  forensicId = rpcResponse[0].forensic_id;
} else if (rpcResponse?.score !== undefined) {
  score = rpcResponse.score;
  alerts = rpcResponse.all_alerts || [];
  forensicId = rpcResponse.forensic_id;
}

console.log(`[Forensic Score] invoice=${supabaseId} score=${score} alerts=${alerts.length}`);

const out = {
  ...original,
  _forensic_score: score,
  _forensic_alerts: alerts,
  _forensic_id: forensicId,
};

// Si score bajo → marcar review pendiente + concatenar razones (sin PATCH adicional;
// el INSERT ya pasó. La función PostgreSQL no puede modificar invoices.review_status retroactivo.
// Aquí lo hace n8n con un cuarto nodo opcional, pero por ahora propagamos el flag).
if (score !== null && score < 50) {
  out.needs_review = true;
  out.ai_razones = (out.ai_razones || []).concat(alerts.map(a => `§FORENSIC:${a}`));
  console.log(`[Forensic Score] FORZAR REVIEW (score<50) invoice=${supabaseId}`);
}

return { json: out, binary: $('Registrar en Supabase').item.binary };

// Llamar PDF Forensic — POST a 172.17.0.1:5001/forensic con b64 del PDF
// Devuelve metadata + alerts del PDF (incremental updates, modificaciones tardías, etc.)
// que enriquecen el Forensic Full Check posterior.
const helpers = this.helpers;
const item = $input.item.json;
const PDF_FORENSIC_URL = ($('Config').first().json.PDF2IMG_URL || 'http://172.17.0.1:5001') + '/forensic';

// Recuperar b64 del PDF cross-node (helper similar al patrón de Construir Prompt)
function getB64() {
  const sources = ['Construir Prompt', 'Convertir a Visión', 'Adaptador Webhook→Pipeline', 'Preparar Pre-Clasificador'];
  for (const src of sources) {
    try {
      const j = $(src).first().json;
      if (j && j._attachment_b64) return j._attachment_b64;
    } catch (e) { /* continuar */ }
  }
  // Fallback: convertir el binary actual si existe
  try {
    if ($input.item.binary && $input.item.binary.data && $input.item.binary.data.data) {
      // n8n almacena binary como objeto con .data (Buffer en base64 si está en json mode)
      const b = $input.item.binary.data;
      if (typeof b.data === 'string') return b.data;
    }
  } catch(e) {}
  return null;
}

const b64 = getB64();
if (!b64) {
  console.log('[PDF Forensic] no se encontró b64 — devolviendo sin alertas');
  return { json: { ...item, _pdf_forensic: { error: 'no_b64_available', alerts: [], metadata: {}, eof_count: null } }, binary: $input.item.binary };
}

let forensicResult = null;
try {
  forensicResult = await helpers.httpRequest({
    method: 'POST',
    url: PDF_FORENSIC_URL,
    body: { pdf_b64: b64 },
    json: true,
    timeout: 8000,
  });
} catch (e) {
  console.log(`[PDF Forensic] error: ${e.message || e}`);
  forensicResult = { error: String(e.message || e).slice(0, 200), alerts: [], metadata: {}, eof_count: null };
}

console.log(`[PDF Forensic] eof_count=${forensicResult.eof_count} alerts=${(forensicResult.alerts || []).length}`);

return { json: { ...item, _pdf_forensic: forensicResult }, binary: $input.item.binary };

const items = $input.all();
const state = {};
for (const it of items) { state[it.json.account] = it.json.last_processed_ts; }
return [{ json: { state, now_ts: Math.floor(Date.now()/1000) } }];

// Normalize Fuzzy → Legacy Shape
// Cutover commit (sesión 16/05 madrugada): sustituye Code Buscar Fuzzy Match
// que hacía httpRequest directo a Supabase REST. Endpoint Vercel
// /api/fuzzy-ticket-invoice ahora gestiona la consulta BD con indexes
// compuestos parciales (idx_invoices_supplier_nif_issue_date WHERE deleted_at IS NULL).
//
// Input: $input.item.json = HTTP response { candidates, query_params, source }
//        o { error, detail } si endpoint devolvió 400/503 con neverError=true.
// Salida: original item + _fuzzy_candidates remapeado para
//         downstream Aplicar Fuzzy Razones (lee c.amount_total || c.total).
const originalItem = $input.item.json;
const response = $input.item.json || {};
const rawCandidates = Array.isArray(response.candidates) ? response.candidates : [];

// Endpoint devuelve {id, number, issue_date, amount, empresa} unificado.
// Downstream lee c.amount_total || c.total. Backfill ambos por compat.
const candidates = rawCandidates.map(c => ({
  ...c,
  amount_total: c.amount,
  total: c.amount,
}));

if (response.error) {
  // Log silente cuando endpoint refused (e.g. NIF vacío, amount=0).
  // Comportamiento idéntico al legacy: candidates=[] y sigue flow.
  console.warn('[Normalize Fuzzy] endpoint error: ' + (response.detail || response.error));
}

return {
  json: Object.assign({}, originalItem, { _fuzzy_candidates: candidates }),
  binary: $input.item.binary,
};

// Normalize Decide Table → Legacy Shape
// Cutover (sesión 16/05 madrugada): sustituye Code Decidir Tabla Destino que
// hacía switch local sobre item.tipo. Endpoint Vercel /api/decide-table v2
// añade además detección código proyecto literal + historial proveedor
// (project_id, project_match_type, project_confidence, action, razones).
//
// Drop-in compat: downstream solo lee item.target_table.
// Enriquecemos item con campos opcionales del endpoint para uso futuro.
//
// Edge: endpoint NUNCA devuelve 'mortgages' (legacy sí, pero FK
// operation_id NOT NULL en mortgages → INSERT fallaba igual). Endpoint
// devuelve invoices needs_review en su lugar (mejor comportamiento).
const originalItem = $('Resolver Project ID').itemMatching($itemIndex).json;
const response = $input.item.json || {};

let target_table = 'invoices';
let _decide_action = null;
let _decide_project_id = null;
let _decide_project_match = null;
let _decide_razones = [];

if (response && typeof response.table === 'string') {
  target_table = response.table;
  _decide_action = response.action || null;
  _decide_project_id = response.project_id || null;
  _decide_project_match = response.project_match_type || null;
  _decide_razones = Array.isArray(response.razones) ? response.razones : [];
} else if (response.error) {
  // Fallback minimal: replica subset de legacy basado en tipo.
  console.warn('[Normalize DecideTable] endpoint error: ' + (response.detail || response.error));
  const tipo = (originalItem.tipo || '').toLowerCase();
  if (tipo === 'presupuesto' || tipo === 'cotizacion') target_table = 'quotes';
  else if (tipo === 'nomina' || tipo === 'nomina_lote') target_table = 'payrolls';
  else if (tipo === 'resumen_nominas') target_table = 'payroll_summaries';
  else if (['contrato','escritura','licencia','informe','seguro','nota_simple'].includes(tipo)) target_table = 'documents';
}

return {
  json: Object.assign({}, originalItem, {
    target_table,
    _decide_action,
    _decide_project_id,
    _decide_project_match,
    _decide_razones,
  }),
  binary: $input.item.binary,
};

// Smart Dedup — construye payload PATCH filtrando campos protegidos.
// Campos protegidos (humano puede haber editado vía admin UI):
//   review_status, reviewed_at, reviewed_by, manually_edited
// Plus: reprocess_attempts se incrementa explícito, no pisamos legacy.
//
// Leer flags + payload desde nodos upstream (no desde $json porque
// Preparar Supabase NO propaga flags Smart Dedup — limitación documentada).
const item = $input.item.json;
const normalize = $('Normalize Dedup → Legacy Shape').item.json;
const dedupResponse = $('HTTP /api/dedup v2').item.json;

const targetTable = item.target_table || 'invoices';

// Seleccionar payload original (mismo switch que Supabase INSERT existente)
const fullPayload =
  targetTable === 'documents' ? (item.documents_payload || {}) :
  targetTable === 'quotes'    ? (item.quotes_payload || {}) :
                                (item.supabase_payload || {});

// Filtrar campos protegidos
const PROTECTED = new Set([
  'review_status', 'reviewed_at', 'reviewed_by',
  'manually_edited',  // trigger BD lo gestiona
  'reprocess_attempts',  // se incrementa explícito abajo
]);
const patchPayload = {};
for (const [k, v] of Object.entries(fullPayload)) {
  if (!PROTECTED.has(k)) {
    patchPayload[k] = v;
  }
}

// Incrementar contador attempts + timestamp
const prevAttempts = dedupResponse.existing_reprocess_attempts ?? 0;
patchPayload.reprocess_attempts = prevAttempts + 1;
patchPayload.last_reprocess_at = new Date().toISOString();

return {
  json: {
    ...item,
    smartDedupPatch: {
      table: targetTable,
      linkedDocId: normalize.linkedDocId,
      existingUpdatedAt: normalize.existingUpdatedAt,
      payload: patchPayload,
    },
  },
  binary: $input.item.binary,
};

// Smart Dedup — verificar optimistic lock no perdió race.
// PATCH con return=representation devuelve array de rows afectadas.
// length=0 → updated_at mismatch → race condition perdida → log warning.
// length=1 → UPDATE success.
const response = $input.item.json;
const rows = Array.isArray(response) ? response : (response?.body ?? []);
const success = Array.isArray(rows) && rows.length === 1;
const raceLost = Array.isArray(rows) && rows.length === 0;

if (raceLost) {
  const normalize = $('Normalize Dedup → Legacy Shape').item.json;
  console.warn(
    '[Smart Dedup] race condition perdida — updated_at mismatch para ' +
    'linkedDocId=' + normalize.linkedDocId + ' existingUpdatedAt=' + normalize.existingUpdatedAt
  );
} else if (success) {
  console.log('[Smart Dedup] PATCH success row id=' + (rows[0]?.id?.slice(0,8) || '?'));
} else {
  console.error('[Smart Dedup] PATCH response inesperado: ' + JSON.stringify(rows).slice(0,200));
}

return {
  json: {
    smartDedupResult: {
      success,
      raceLost,
      rowsAffected: Array.isArray(rows) ? rows.length : 0,
      response: response,
    },
  },
  binary: $input.item.binary,
};

// Smart Routing Capa A — File Type Detector (Sesión 17/05/2026)
// Stage 0: magic bytes JS in-process (<5ms)
// Stage 1: PDF → HTTP /probe-pdf Hetzner (text-layer probe)
// Stage 2: XML → root namespace regex Facturae ES / UBL EU
//
// Output _archive_type categorías:
//   ARCHIVO_PDF_TEXTO_NATIVO      → Capa B route a pdfplumber/Gemini Pro
//   ARCHIVO_PDF_ESCANEADO         → Capa B route a Gemini Pro vision
