//   ARCHIVO_XML_FACTURAE_ES       → Capa B parser XSD ($0 LLM)
//   ARCHIVO_XML_UBL_EU            → Capa B parser XSD ($0 LLM)
//   ARCHIVO_XML_UNKNOWN
//   ARCHIVO_OFFICE_DOCX/XLSX
//   ARCHIVO_DESCONOCIDO

const item = $input.item.json;
const cfg = $('Config').first().json;
const fileExtension = (item.fileExtension || '').toLowerCase();
const binaryProp = item.binaryPropertyName || 'attachment_0';

let buffer;
try {
  buffer = await this.helpers.getBinaryDataBuffer($itemIndex, binaryProp);
} catch (e) {
  console.warn('[Smart Routing A] getBinaryDataBuffer failed: ' + e.message);
  return {
    json: { ...item, _archive_type: 'ARCHIVO_DESCONOCIDO', _archive_mime: 'application/octet-stream', _archive_detector_error: e.message },
    binary: $input.item.binary,
  };
}

