  archiveType = 'ARCHIVO_PDF_GENERICO';
  probeNeeded = true;
} else if (hex.startsWith('ffd8ff')) {
  mimeType = 'image/jpeg';
  archiveType = 'ARCHIVO_IMAGEN_JPEG';
} else if (hex.startsWith('89504e47')) {
  mimeType = 'image/png';
  archiveType = 'ARCHIVO_IMAGEN_PNG';
} else if (hex.startsWith('47494638')) {
  mimeType = 'image/gif';
  archiveType = 'ARCHIVO_IMAGEN_GIF';
