  // RIFF — could be WEBP, AVI, WAV. Check bytes 8-11 for WEBP signature.
  const subType = hex.substring(16, 24);  // bytes 8-11
  if (subType === '57454250') {
    mimeType = 'image/webp';
    archiveType = 'ARCHIVO_IMAGEN_WEBP';
  } else {
    archiveType = 'ARCHIVO_DESCONOCIDO';
  }
