    hex.substring(16, 24) === '68656963' ||  // heic
    hex.substring(16, 24) === '68656978' ||  // heix
    hex.substring(16, 24) === '6d696631' ||  // mif1
    hex.substring(16, 24) === '6d736631' ||  // msf1
    hex.substring(16, 24) === '68657663'     // hevc
