  hex.startsWith('3c3f786d6c') ||  // <?xml
  hex.startsWith('3c46616374') ||  // <Facturae
  hex.startsWith('3c66653a') ||    // <fe:
  hex.startsWith('3c496e766f')     // <Invoice
