    archiveType = 'ARCHIVO_IMAGEN_JPEG';
  } else if (fileExtension === 'png') {
    mimeType = 'image/png';
    archiveType = 'ARCHIVO_IMAGEN_PNG';
  } else if (fileExtension === 'heic') {
