// Filtrar spam/newsletters obvios
const spamPatterns = cfg.SPAM_PATTERNS;
const isSpam = spamPatterns.some(p => fromStr.includes(p) || subject.includes(p));

// SAFETY NET: si tiene attachment "relevante" (PDF/imagen >10KB), NO descartar aunque parezca spam
// Esto evita falsos positivos como "Promo + factura.pdf adjunta"
const binary = $input.item.binary || {};
const hasRelevantAttachment = Object.values(binary).some(b => {
  const ext = (b.fileName || '').split('.').pop().toLowerCase();
  const supported = ['pdf','jpg','jpeg','png','gif','bmp','tiff','webp','heic'];
  if (!supported.includes(ext)) return false;
  // fileSize puede venir como '12.3 kB' string o number
  const sizeRaw = b.fileSize;
  const sizeBytes = typeof sizeRaw === 'number' ? sizeRaw :
    typeof sizeRaw === 'string' ? parseFloat(sizeRaw) * (sizeRaw.includes('kB') ? 1024 : sizeRaw.includes('MB') ? 1048576 : 1) : 0;
  return sizeBytes >= 10240; // >=10KB
});

if (isSpam && !hasRelevantAttachment) {
  console.log('Descartado por spam patterns sin adjunto relevante:', fromStr, subject);
  return [];
}
