const attachmentB64 = visionItem._attachment_b64 || promptItem._attachment_b64;
const attachmentMime = visionItem._attachment_mime || promptItem._attachment_mime || 'image/jpeg';

const imageParts = [];

if (visionImages.length > 0) {
  // Caso normal: PDF convertido a imágenes (1 por página)
  for (const imgB64 of visionImages) {
    if (!imgB64) continue;
    imageParts.push({
      type: 'image_url',
      image_url: {
        url: 'data:image/jpeg;base64,' + imgB64,
        detail: 'high'
      }
    });
  }
} else if (attachmentB64 && attachmentMime.startsWith('image/')) {
  // Imagen original (sin necesidad de convertir)
  imageParts.push({
    type: 'image_url',
