let result = {};
try {
  result = JSON.parse(rawContent.trim());
} catch(e) {
  // Si falla el parseo: conservador, asumir financiero (mejor procesar de más que perder facturas)
  console.warn('Pre-clasificador: error parseo JSON, conservando doc:', rawContent.substring(0, 100));
  result = { es_financiero: true, confianza: 0.5, tipo_probable: 'desconocido' };
}

const esFinanciero = result.es_financiero !== false;
const confianza = parseFloat(result.confianza) || 0.5;

// Solo descartar si el clasificador está MUY seguro de que no es financiero
if (!esFinanciero && confianza >= cfg.PRE_CLASSIFY_THRESHOLD) {
  const fname = originalRest.fileName || originalRest.attachmentData?.name || '';
  console.log(`Pre-clasificador descartó: "${fname}" | tipo: ${result.tipo_probable} | razón: ${result.razon}`);
