// Resolver Project ID — versión sesión 8/05/2026 v3 (mejoras fuzzy match)
// Cambios sobre v2:
//   - Stop words ampliados con datos Cathedral propios (anti-falsos-positivos
//     cuando la factura cita al receptor en lugar del proyecto)
//   - Path 1 robusto: si Gemini devolvió proyecto_code con variantes de formato
//     (OBR2025005 vs OBR-2025-005), normalizar y comparar
//   - Path 2 enriquecido: bonus por match del nombre/NIF del cliente del proyecto
//   - Filtro de números: descartar años (2020-2030), NIF, importes
//
// Reglas de auto-asignación:
//   1) Si Gemini devolvió proyecto_code → resolver UUID directo (con normalización).
//   2) Si no: matching fuzzy contra projects.name + projects.address + projects.client.
//      - Tokens significativos (>=4 chars, sin stop-words)
//      - Bonus strong match (>5 chars) +2
//      - Bonus si número de calle coincide (excluyendo años/NIF/importes) +2
//      - Bonus si nombre o NIF del cliente del proyecto aparece +2
//      - 1 candidato → auto. 2+ con top dominante (>=+2 vs siguiente) → auto.
//      - Empate → sugerir, sin auto-asignar.

const item = $input.item.json;
const proyectos = item.proyectos_activos || [];
const proyecto_code_input = item.proyecto_code || null;

const STOP_WORDS = new Set([
  // Genéricos español
  'calle','avenida','plaza','madrid','reforma','obra','numero','num','de','del',
  'la','el','los','las','en','con','por','para','sin','sobre','entre','cliente',
  'factura','presupuesto','albaran','certificado','contrato','seguro','licencia',
  'documento','copia','original','provincia','codigo','postal','total','pais',
  'iva','irpf','base','imponible','importe','euro','euros','fecha','vencimiento',
  // Datos del receptor Cathedral (NUNCA deberían sumar score como si fueran del proyecto)
  'cathedral','group','house','investment','b19761915','sociedad','limitada',
  'constructora','inmobiliaria','reformas',
]);

function normalizeText(s) {
  return (s || '').toString().toLowerCase()
    .normalize('NFD').replace(/[̀-ͯ]/g, '')
    .replace(/[^a-z0-9\s]/g, ' ');
}

function normalizeCode(s) {
  // OBR-2025-005 → obr2025005 (quita guiones, ceros líderes opcionales en última parte)
  return (s || '').toString().toLowerCase().replace(/[^a-z0-9]/g, '');
}

function projectKeywords(p) {
  const text = ((p.name || '') + ' ' + (p.address || '')).toLowerCase();
  const norm = normalizeText(text);
  const words = norm.split(/\s+/).filter(Boolean);
  const significant = words.filter(w => w.length >= 4 && !STOP_WORDS.has(w));
  // Número de calle: 1-4 dígitos, excluyendo años (2020-2030) y números muy comunes
  const candidates = (text.match(/\b(\d{1,4})\b/g) || [])
    .map(n => parseInt(n, 10))
    .filter(n => !(n >= 2020 && n <= 2030) && n !== 0 && !isNaN(n));
  const num = candidates.length > 0 ? String(candidates[0]) : null;
  return { words: [...new Set(significant)], num };
}

function clientTokens(p) {
  // Tokens del cliente del proyecto: nombre + nif si existen
  const c = p.client || {};
  const name = (c.name || c.company_name || '').toString();
  const nif = (c.nif_cif || '').toString();
  const tokens = [];
  if (name) {
    const norm = normalizeText(name);
    norm.split(/\s+/).filter(w => w.length >= 4 && !STOP_WORDS.has(w))
      .forEach(w => tokens.push({ token: w, kind: 'client_name' }));
  }
  if (nif && nif.length >= 8) {
    tokens.push({ token: nif.toLowerCase().replace(/[^a-z0-9]/g, ''), kind: 'client_nif' });
  }
  return tokens;
}

let project_id = null;
let proyecto_code = proyecto_code_input;
let proyecto_sugerido_code = null;
let proyecto_sugerido_razon = null;
let matchSource = 'none';

// Path 1: Gemini detectó proyecto_code → resolver UUID (con normalización)
if (proyecto_code_input) {
  const inputNorm = normalizeCode(proyecto_code_input);
  // Match exacto primero
  let match = proyectos.find(p => p.code === proyecto_code_input);
  // Match por normalización si no exacto
  if (!match) {
    match = proyectos.find(p => normalizeCode(p.code) === inputNorm);
    if (match) matchSource = 'gpt_code_normalized';
  } else {
    matchSource = 'gpt_direct';
  }
  if (match) {
    project_id = match.id;
    proyecto_code = match.code; // siempre normalizar al code canónico de BD
  } else {
    matchSource = 'gpt_code_unknown';
  }
}

// Path 2: fuzzy matching si Gemini no resolvió
if (!project_id && proyectos.length > 0) {
  const textoBusqueda = normalizeText([
    item.fileName || '',
    item.originalFileName || '',
    item.concept || '',
    item.direccion_obra || '',
    item.notas_documento || '',
    (item.texto_extraido || '').substring(0, 1500),
  ].join(' '));

  const candidatos = [];
  for (const p of proyectos) {
    const kw = projectKeywords(p);
    if (kw.words.length === 0) continue;

    let matches = 0, strongMatches = 0;
    const matchedWords = [];
    for (const w of kw.words) {
      const re = new RegExp('\\b' + w.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '\\b');
      if (re.test(textoBusqueda)) {
        matches++;
        matchedWords.push(w);
        if (w.length > 5) strongMatches++;
      }
    }

    let score = matches + (strongMatches * 2);
    let numMatch = false;
    if (kw.num && new RegExp('\\b' + kw.num + '\\b').test(textoBusqueda)) {
      score += 2;
      numMatch = true;
    }

    // Bonus por match del cliente del proyecto
    let clientMatch = false;
    const ctokens = clientTokens(p);
    for (const ct of ctokens) {
      if (!ct.token) continue;
      if (ct.kind === 'client_nif') {
        // NIF: buscar en texto sin separadores
        const cleanText = textoBusqueda.replace(/[^a-z0-9]/g, '');
        if (cleanText.includes(ct.token)) {
          score += 2;
          clientMatch = true;
          break;
        }
      } else {
        const re = new RegExp('\\b' + ct.token.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '\\b');
        if (re.test(textoBusqueda)) {
          score += 2;
          clientMatch = true;
          break;
        }
      }
    }

    // Considerar candidatos con: 1 strong match, score>=3, O match del cliente
    // (el cliente es señal fuerte por sí sola — NIF/nombre del cliente del proyecto
    // apareciendo en una factura es un indicador suficiente)
    if (strongMatches >= 1 || score >= 3 || clientMatch) {
      candidatos.push({ p, score, matches, strongMatches, words: matchedWords, numMatch, clientMatch });
    }
  }

  candidatos.sort((a, b) => b.score - a.score);

  if (candidatos.length === 1) {
    const c = candidatos[0];
    project_id = c.p.id;
    proyecto_code = c.p.code;
    const tags = [];
    if (c.numMatch) tags.push('num');
    if (c.clientMatch) tags.push('client');
    matchSource = `fuzzy_unique:${c.words.join(',')}${tags.length ? ',' + tags.join(',') : ''}`;
  } else if (candidatos.length >= 2) {
    const top = candidatos[0];
    const second = candidatos[1];
    if (top.score - second.score >= 2) {
      project_id = top.p.id;
      proyecto_code = top.p.code;
      const tags = [];
      if (top.numMatch) tags.push('num');
      if (top.clientMatch) tags.push('client');
      matchSource = `fuzzy_dominant:${top.words.join(',')}${tags.length ? ',' + tags.join(',') : ''} (vs ${second.p.code} score ${second.score})`;
    } else {
      proyecto_sugerido_code = top.p.code;
      proyecto_sugerido_razon = `fuzzy ambiguo: ${top.p.code}(${top.score}) vs ${second.p.code}(${second.score})`;
      matchSource = 'fuzzy_ambiguous';
    }
  }
}

if (matchSource === 'none' && !proyecto_code_input) {
  matchSource = 'sin_indicio';
}

console.log(`[Resolver Project ID v3] code=${proyecto_code || '-'} project_id=${project_id || '-'} source=${matchSource}`);

return {
  json: {
    ...item,
    project_id,
    proyecto_code,
    proyecto_sugerido_code: proyecto_sugerido_code || item.proyecto_sugerido_code || null,
    proyecto_sugerido_razon: proyecto_sugerido_razon || item.proyecto_sugerido_razon || null,
    _project_match_source: matchSource,
  },
  binary: $input.item.binary
};

// Buscar Historial Proveedor V2 (sesion 14/05/2026)
// REEMPLAZO HTTP Request node v4.2 con Code que preserva item.json original
// + anade _historial_proveedor. Fix bug pairedItem collapse 4->1.
// Research-based: github.com/n8n-io/n8n PR #25203 + community 285889.

const item = $input.item.json;
const cfg = $('Config').first().json;
const SUPABASE_URL = (cfg.SUPABASE_URL || 'https://cpqsnajuypgjjapvbqsr.supabase.co').replace(/\/rest\/v1\/?$/, '');
const SUPABASE_SECRET = $env.SUPABASE_SECRET_KEY;
const supplier_nif = item.supplier_nif || item.nif_emisor || '';

let historial = [];
if (SUPABASE_SECRET && supplier_nif) {
  try {
    const url = SUPABASE_URL + '/rest/v1/invoices?supplier_nif=eq.' + encodeURIComponent(supplier_nif) + '&project_id=not.is.null&deleted_at=is.null&select=project_id,proyecto_code,empresa,created_at,amount_total,doc_type&order=created_at.desc&limit=30';
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url: url,
      headers: {
        apikey: SUPABASE_SECRET,
        Authorization: 'Bearer ' + SUPABASE_SECRET,
        Accept: 'application/json'
      },
      json: true,
      timeout: 10000,
      ignoreHttpStatusErrors: true
    });
    historial = Array.isArray(resp) ? resp : [];
  } catch (e) {
    console.warn('[Buscar Historial Proveedor Code] HTTP failed: ' + e.message);
    historial = [];
  }
}

return {
  json: Object.assign({}, item, { _historial_proveedor: historial }),
  binary: $input.item.binary
};

// Refinar con Historial Proveedor — v2
// REGLA CENTRAL: la IA nunca auto-asigna sola.
// Para auto-asignar se necesita la IA + al menos una señal corroborante independiente.
// Sin corroboración → siempre sugerencia. Esto garantiza 0 falsos positivos.

// V2 14/05/2026: Buscar Historial Proveedor ahora preserva item original + anade _historial_proveedor
const item = $input.item.json;
const historialRaw = item._historial_proveedor || [];

const historial = Array.isArray(historialRaw) ? historialRaw : [];

// Contar facturas por proyecto en el historial del proveedor
const countByProject = {};
let historialTotal = 0;
historial.forEach(inv => {
  if (inv.project_id) {
    countByProject[inv.project_id] = (countByProject[inv.project_id] || 0) + 1;
    historialTotal++;
  }
});

// Proyecto más frecuente en historial + % lealtad
let histTop = null, histTopCount = 0;
Object.entries(countByProject).forEach(([pid, cnt]) => {
  if (cnt > histTopCount) { histTopCount = cnt; histTop = pid; }
});
const histTopLoyalty = historialTotal > 0 ? histTopCount / historialTotal : 0;

const proyectos_activos = item.proyectos_activos || [];
const getCode = (pid) => { const p = proyectos_activos.find(p => p.id === pid); return p ? p.code : null; };
const getId  = (code) => { const p = proyectos_activos.find(p => p.code === code); return p ? p.id : null; };

let proyecto_code         = item.proyecto_code         || null;
let proyecto_confianza    = item.proyecto_confianza    || 0;
let proyecto_razon        = item.proyecto_razon        || '';
let proyecto_code_sugerido = item.proyecto_code_sugerido || null;

const histTopCode = histTop ? getCode(histTop) : null;

// ═══════════════════════════════════════════════════════════════
// DETECTAR SEÑALES CORROBORANTES (independientes de la IA)
// ═══════════════════════════════════════════════════════════════
let hasCorroboration = false;
let corroborationReason = '';

// — Señal 1: Código de proyecto encontrado literalmente en el texto —
const textoFactura = [
  item.concept      || '',
  item.notes        || '',
  item.numero       || item.number || '',
  item.attachmentData?.emailSubject || item.emailSubject || '',
  (item.attachmentData?.emailBody   || item.emailBody   || '').substring(0, 3000),
].join(' ').toUpperCase();

if (proyecto_code) {
  const codeNorm = proyecto_code.replace(/[-_ ]/g, '');
  const re = new RegExp('\\b' + codeNorm + '\\b');
  if (re.test(textoFactura.replace(/[-_ ]/g, ''))) {
    hasCorroboration = true;
    corroborationReason = `Código "${proyecto_code}" encontrado literalmente en el documento/correo`;
  }
}

// — Señal 2: Historial del proveedor confirma la asignación de la IA —
if (!hasCorroboration && proyecto_code && histTopCode === proyecto_code && histTopCount >= 2) {
  hasCorroboration = true;
  corroborationReason = `Historial confirma: ${histTopCount} facturas previas asignadas a ${proyecto_code}`;
  const boost = Math.min(0.08, histTopCount * 0.02);
  proyecto_confianza = Math.min(0.99, proyecto_confianza + boost);
}

// — Señal 3: Alta lealtad del proveedor al proyecto asignado por la IA (≥70%, mín 3 facturas) —
if (!hasCorroboration && proyecto_code) {
  const aiProjectId = getId(proyecto_code);
  const aiCount     = aiProjectId ? (countByProject[aiProjectId] || 0) : 0;
  const aiLoyalty   = historialTotal > 0 ? aiCount / historialTotal : 0;
  if (aiCount >= 3 && aiLoyalty >= 0.70) {
    hasCorroboration = true;
    corroborationReason = `Lealtad proveedor: ${Math.round(aiLoyalty*100)}% de sus facturas en ${proyecto_code} (${aiCount}/${historialTotal})`;
    proyecto_confianza = Math.min(0.99, proyecto_confianza + 0.05);
  }
}

// ═══════════════════════════════════════════════════════════════
// PUERTA FINAL: sin corroboración → siempre sugerencia
// ═══════════════════════════════════════════════════════════════
if (proyecto_code && !hasCorroboration) {
  console.log(`Sin corroboración para "${proyecto_code}" (conf=${proyecto_confianza.toFixed(2)}) → movido a sugerencia`);
  proyecto_code_sugerido = proyecto_code_sugerido || proyecto_code;
  proyecto_razon = proyecto_razon + ` | IA sin corroboración → sugerencia pendiente de confirmación`;
  proyecto_code = null;
}

if (proyecto_code && hasCorroboration) {
  proyecto_razon = proyecto_razon + ` | ✓ Corroborado: ${corroborationReason}`;
  console.log(`Auto-asignación confirmada: ${proyecto_code} — ${corroborationReason}`);
}

// ═══════════════════════════════════════════════════════════════
// HISTORIAL SIN IA: proveedor con lealtad exclusiva
// ═══════════════════════════════════════════════════════════════
if (!proyecto_code && !proyecto_code_sugerido && histTopCode) {
  if (histTopCount >= 5 && histTopLoyalty >= 0.85) {
    // Lealtad casi exclusiva → auto-asigna por historial solo
    proyecto_code     = histTopCode;
    proyecto_confianza = Math.min(0.95, 0.70 + histTopLoyalty * 0.25);
    proyecto_razon    = `Lealtad exclusiva proveedor: ${Math.round(histTopLoyalty*100)}% (${histTopCount} facturas) en ${histTopCode}`;
    console.log(`Lealtad exclusiva → auto-asigna: ${histTopCode} (${Math.round(histTopLoyalty*100)}%)`);
  } else if (histTopCount >= 2) {
    // Sugiere basado en historial
    proyecto_code_sugerido = histTopCode;
    proyecto_confianza     = Math.min(0.82, 0.45 + histTopCount * 0.05 + histTopLoyalty * 0.20);
    proyecto_razon         = `Historial proveedor: ${histTopCount} facturas en ${histTopCode} (${Math.round(histTopLoyalty*100)}% del total)`;
    console.log(`Historial sugiere: ${histTopCode} (${histTopCount} facturas)`);
  }
}

// ═══════════════════════════════════════════════════════════════
// HISTORIAL CONTRADICE LA SUGERENCIA DE IA → avisar
// ═══════════════════════════════════════════════════════════════
if (proyecto_code_sugerido && histTopCode && histTopCode !== proyecto_code_sugerido && histTopCount >= 4) {
  proyecto_razon     = proyecto_razon + ` ⚠ Conflicto: IA sugiere ${proyecto_code_sugerido} pero historial apunta a ${histTopCode} (${histTopCount} facturas)`;
  proyecto_confianza = Math.min(proyecto_confianza, 0.60);
}

// ═══════════════════════════════════════════════════════════════
// HISTORIAL APOYA LA SUGERENCIA DE IA → refuerza confianza
// ════════════════════════════════����═���════════════════════════════
if (!proyecto_code && proyecto_code_sugerido && histTopCode === proyecto_code_sugerido && histTopCount >= 2) {
  const boost = Math.min(0.08, histTopCount * 0.02);
  proyecto_confianza = Math.min(0.90, (proyecto_confianza || 0.65) + boost);
  proyecto_razon     = proyecto_razon + ` | Historial apoya sugerencia: ${histTopCount} facturas en ${proyecto_code_sugerido}`;
}

return {
  json: { ...item, proyecto_code, proyecto_confianza, proyecto_razon, proyecto_code_sugerido },
  binary: $input.item.binary
};

