// V10 (19/05/2026): support admin/worker upload paths + fallback _attachment_b64 cross-node reconstruction
const router = $('Router Carpeta Destino').first();

async function getVisionBinary() {
  // Path 1: Gmail (Adaptador Webhook→Pipeline)
  try {
    const ref = $('Adaptador Webhook→Pipeline').itemMatching($itemIndex);
    if (ref?.binary && Object.keys(ref.binary).length > 0) return ref.binary;
  } catch (e) {}
  // Path 2: Admin/Worker upload (Adaptador Admin Upload)
  try {
    const ref = $('Adaptador Admin Upload').itemMatching($itemIndex);
    if (ref?.binary && Object.keys(ref.binary).length > 0) return ref.binary;
  } catch (e) {}
  // Fallback: reconstruir desde _attachment_b64
  let b64 = null;
  for (const nm of ['Adaptador Admin Upload', 'Adaptador Webhook→Pipeline']) {
    try {
      const ref = $(nm).first().json;
      if (ref?._attachment_b64) { b64 = ref._attachment_b64; break; }
    } catch (e) {}
  }
  if (!b64) return {};
  const filename = router.json?.newFileName || router.json?.fileName || 'file.jpg';
  const mimeType = router.json?.mime_type || 'image/jpeg';
  const buffer = Buffer.from(b64, 'base64');
  const binData = await this.helpers.prepareBinaryData(buffer, filename, mimeType);
  return { attachment_0: binData };
}

const visionBinary = await getVisionBinary();
return {
